// // This module implements an asynchronous 8-bit down counter that decrements its count output when a falling edge on the 'in' input is detected, provided the 'reset' input is not active. The counter periodically resets to zero when the 'reset' signal is asserted. The design also incorporates edge detection for the 'in' signal, ensuring that the count decrements only on the first falling edge of 'in' following a high state.
module top_module(
    input wire clk,
    input wire reset,
    input wire in,
    output reg [7:0] count_out
);reg in_prev;

always @(posedge clk, posedge reset) begin
    if (reset) begin
        count_out <= 0;
        in_prev <= 0;
    end
    else begin
        if (in && !in_prev) begin
            count_out <= count_out + 1;
        end
        in_prev <= in;
    end
end

endmodule
